import{_ as t,o as e,c as i,a as s}from"./app-2a089349.js";const n={},o=s('<h1 id="stripe-faq-how-do-subscriptions-handle-staging-sites-and-migrations" tabindex="-1"><a class="header-anchor" href="#stripe-faq-how-do-subscriptions-handle-staging-sites-and-migrations" aria-hidden="true">#</a> Stripe FAQ - How Do Subscriptions Handle Staging Sites and Migrations?</h1><p>When working on Staging Sites and planning on migrating to another site or live site, you need to check the following:</p><ol><li>The Stripe Webhook should match the URL of your live or staging site( see <a href="/docs-v3/um-stripe/article/1607-stripe-setting-up-webhook-and-test-public-keys">Webhook Settings</a> ). You can check the Webhook URL in Ultimate <strong>Member &gt; Settings &gt; Extensions &gt; Stripe.</strong></li><li>Stripe Pages should be generated or <strong><a href="/docs-v3/um-stripe/article/1900-how-to-create-stripe-pages-manually">created in WP-Admin Pages</a></strong> and assigned in <strong>Ultimate Member &gt; Settings &gt; General Pages</strong></li><li>Stripe API Keys should be set in <strong>Ultimate Member &gt; Settings &gt; Extensions &gt; Stripe</strong>.</li><li>Stripe Plans are built with a Custom Post Type ( umm_stripe ), which means that this can be imported with popular import posts/pages plugins.</li></ol>',3),a=[o];function r(g,l){return e(),i("div",null,a)}const c=t(n,[["render",r],["__file","1612-stripe-faq-how-do-subscriptions-handle-staging-sites-and-migrations.html.vue"]]);export{c as default};
